const items = $input.all();

if (items.length === 0) {
  return [];
}

let emailBody = `
<div style="font-family: Arial, sans-serif; max-width: 600px;">
  <h2 style="color: #1DB954;">🎸 ${items.length} nová zmínka${items.length > 1 ? 'y' : ''} o ${$('Set Config').item.json.keyword} !</h2>
  <p style="color: #666;">I found these new mentions in the last 24 hours:</p>
`;

for (const item of items) {
  emailBody += `
    <div style="margin: 20px 0; padding: 15px; border-left: 4px solid #1DB954; background: #f9f9f9;">
      <h3 style="margin: 0 0 10px 0; color: #333;">${item.json.title}</h3>
      <p style="margin: 5px 0;"><strong>📰 Zdroj:</strong> ${item.json.source} (${item.json.domain})</p>
      <p style="margin: 5px 0;"><strong>📅 Published:</strong> ${item.json.published}</p>
      <p style="margin: 5px 0;"><strong>🔗 Link:</strong> <a href="${item.json.url}" style="color: #1DB954;">${item.json.url}</a></p>
      <p style="margin: 10px 0 0 0; color: #666; font-style: italic;">${item.json.snippet}</p>
    </div>
  `;
}

emailBody += `
  <hr style="margin: 30px 0; border: none; border-top: 1px solid #ddd;">
  <p style="color: #999; font-size: 12px;">You can find all mentions in Google Sheets. This email was generated automatically by n8n workflow.</p>
</div>
`;

return [{
  json: {
    subject: `🎸 ${items.length} new mention${items.length > 1 ? 'y' : ''} about ${$('Set Config').item.json.keyword} !`,
    body: emailBody,
    count: items.length
  }
}];

const keyword = $input.first().json.keyword;
const description = $input.first().json.description;

const dorky = [
  `"${keyword}" music`,
  `"${keyword}" concert`,
  `"${keyword}" festival`,
  `"${keyword}" album`,
  `"${keyword}" band`,
  `("${keyword}" OR "${keyword.replace(' ', '')}") AND (music OR concert OR festival OR release)`
];

const bannedDomains = [
  'spotify.com',
  'open.spotify.com',
  'music.apple.com',
  'bandcamp.com',
  'soundcloud.com',
  'youtube.com',
  'youtu.be',
  'instagram.com',
  'facebook.com',
  'twitter.com',
  'x.com',
  'tiktok.com',
  'linktr.ee'
];

// Vrať array - každý dork jako samostatný item
return dorky.map(dork => ({
  json: {
    currentDork: dork,
    keyword: keyword,
    description: description,
    bannedDomains: bannedDomains,
    timeRange: 'pd'  // past day pro Brave API
  }
}));

