// Get the AI output
const aiData = $input.first().json;
let aiResult;

try {
  // Extract the text object from the nested structure
  aiResult = aiData.output[0].content[0].text;
} catch (e) {
  // Fallback if structure is different
  aiResult = {
    isRelevant: false,
    confidence: 'low',
    reason: 'Failed to parse AI response'
  };
}

// Get the original data from Extract Data node
const originalData = $('Extract Data').item.json;

// Merge everything together
return [{
  json: {
    url: originalData.url,
    title: originalData.title,
    source: originalData.source,
    domain: originalData.domain,
    published: originalData.published,
    snippet: originalData.snippet,
    isRelevant: aiResult.isRelevant,
    verificationConfidence: aiResult.confidence,
    verificationReason: aiResult.reason
  }
}];
